from collections import Counter

class Solution:
    def findXSum(self, nums, k, x):
        n = len(nums)
        res = []
        for i in range(n - k + 1):
            cnt = Counter(nums[i:i + k])
            items = sorted(cnt.items(), key=lambda p: (-p[1], -p[0]))
            res.append(sum(v * c for v, c in items[:x]))
        return res

