var findXSum = function(nums, k, x) {
    const n = nums.length;
    const res = [];
    for (let i = 0; i + k <= n; i++) {
        const cnt = new Map();
        for (let j = i; j < i + k; j++) {
            cnt.set(nums[j], (cnt.get(nums[j]) || 0) + 1);
        }
        const items = [...cnt.entries()].sort((a, b) => (b[1] - a[1]) || (b[0] - a[0]));
        let total = 0;
        for (let t = 0; t < Math.min(x, items.length); t++) {
            total += items[t][0] * items[t][1];
        }
        res.push(total);
    }
    return res;
};
